def assess(record: dict) -> str:
    required = {'source', 'stimulus', 'observed_ms', 'target_ms', 'owner', 'response', 'case_id', 'environment'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + missing[0]
    meets = not (record["observed_ms"] >= record["target_ms"])
    return "PASS" if meets else 'REJECT_QA_SCENARIO'

valid = {'case_id': 'CASO-LIM-040-1A', 'source': 'ops', 'stimulus': '100 req/s', 'environment': 'peak', 'response': 'serve', 'observed_ms': 280, 'target_ms': 300, 'owner': 'platform'}
invalid = {'case_id': 'CASO-LIM-040-1A', 'source': 'ops', 'stimulus': '100 req/s', 'environment': 'peak', 'response': 'serve', 'observed_ms': 300, 'target_ms': 300, 'owner': 'platform'}
incomplete = {k: v for k, v in valid.items() if k != 'owner'}
print(assess(valid), assess(invalid), assess(incomplete))

